import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./../styles/Auth.css";
import { toast } from "react-toastify"; 
import "react-toastify/dist/ReactToastify.css";

const Login = () => {
  const [libraryId, setLibraryId] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    const response = await fetch("http://localhost:5000/auth/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ libraryId, email, password }),
    });

    const data = await response.json();
    if (response.ok) {
      toast.success("Login Successful ✅", { position: "top-center", autoClose: 3000 });
  
      localStorage.setItem("token", data.token);
      localStorage.setItem("role", email === "ishwaryarajendran77@gmail.com" ? "admin" : "user");
  
      setTimeout(() => {
        navigate(email === "ishwaryarajendran77@gmail.com" ? "/admin-dashboard" : "/dashboard");
      }, 3000);
    } else {
      toast.error(data.message, { position: "top-center", autoClose: 3000 });
    }
  };
  
  return (
    <div className="auth-container">
      <div className="auth-box">
        <h2>📚 Library Login</h2>
        {error && <p className="error">{error}</p>}
        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Library ID" value={libraryId} onChange={(e) => setLibraryId(e.target.value)} required />
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
          <button type="submit">Login</button>
        </form>
        <p>New to the library? <span onClick={() => navigate("/signup")}>Sign up</span></p>
      </div>
    </div>
  );
};

export default Login;
